import React from "react";
import Link from "next/link";
import { getCategories } from "@/api_call/api";
export default async function page() {
  const category_res = await getCategories({is_top:true,status:true})
  const categories = category_res?.data;
  const imagePath = category_res?.meta?.imagebaseurl;
  return (
    <div className="py-10 px-10 bg-white rounded-4xl shadow-xl">
  <h1 className="text-xl mb-10 font-bold text-black">
    Top Categories
  </h1>

  <div className="ps-5 grid grid-cols-4 gap-16">
    {categories.map((item, index) => {
      return (
        <div
          key={index}
          className="flex flex-col items-center justify-between h-25 text-center"
        >
            <Link href={"/"} >
            <img
            src={imagePath + item.image}
            alt="brand"
            className="h-10 rounded-xl   object-contain"
          />
            </Link>
          <Link href="/" className="mt-2 font-semibold hover:bg-gray-200 rounded-2xl p-1">{item.name}</Link>
        </div>
      );
    })}
  </div>
</div>
  );
}
