import React from 'react'
import AddToCartButton from './AddToCart';
import { getMe } from '@/api_call/serverApi';

export default async function ProductCard({items ,}) {
  const user = await  getMe()
    return (
      <div  className="group bg-white rounded-md p-4 shadow-sm w-[260px] transition-all duration-300 hover:shadow-lg hover:-translate-y-1">
        {/* Badge */}
        <div className="flex justify-between items-start">
          <span className="bg-green-500 text-white text-xs px-3 py-1 rounded-md font-semibold">
            SAVE $59.00
          </span>
          <div className="w-6 h-6 bg-gray-200 rounded-full transition group-hover:bg-gray-300" />
        </div>
  
        {/* Image */}
        <div className="flex justify-center my-4 overflow-hidden">
          <img
            src={`http://localhost:5000/product/${items.thumbnail}`}
            className="h-20 object-contain transition-transform duration-300 group-hover:scale-110"
          />
        </div>
  
        {/* Divider Count */}
        <div className="text-center text-xs text-gray-400 mb-2">(8)</div>
  
        <h3 className="text-sm font-semibold text-gray-400 leading-snug transition-colors">
          {items?.brandId?.name}
        </h3>

        {/* Title */}
        <h3 className="text-sm font-semibold text-gray-900 leading-snug transition-colors group-hover:text-black">
          {items?.name}
        </h3>
      
  
        {/* Price */}
        <div className="mt-2 flex items-center gap-2">
          <span className="text-black font-bold text-lg">${items?.final_price}</span>
          <span className="text-gray-400 line-through text-sm">${items?.original_price}</span>
        </div>
  
        {/* Shipping */}
        <div className="mt-2">
          <span className="bg-green-100 text-green-600 text-xs px-2 py-1 rounded font-semibold">
            FREE SHIPPING
          </span>
        </div>
  
        {/* Stock */}
        <div className="flex items-center gap-2 mt-2 text-sm text-gray-500">
          <span className={items.status ? "text-green-500" :"text-red-500" }>●</span>
          {items?.status ? " In stock" :  "Out of stock "}
         
        </div>
  
        {/* Buttons */}
        <div className="mt-4 flex gap-2">
         <AddToCartButton user={user} product={items}/>
        </div>
      </div>
    );
  }
  
  