import React from "react";
import Image from "next/image";
import { IoMdShareAlt } from "react-icons/io";
import Link from "next/link";
import { getCategories } from "@/api_call/api";

export default async function Hero() {
 const catRes = await getCategories({limit:5,is_home:true,status:true})
 const categories = catRes?.data;
 const imagePath = catRes?.meta?.imagebaseurl;
  return (
    <div className="bg-gray-200">
      <div className="flex gap-5 py-5 max-w-7xl mx-auto">
        <div className="bg-white p-6 flex-1 shadow-xl rounded-2xl">
          <h1 className="text-[#253D4E] text-2xl">Category</h1>
          <ul className="mt-2">
            {categories.map((items, index,) => {
              return (
                <Link key={index} href={"/category"}>
                  <li className="flex border border-gray-300  py-2 px-2 rounded-xl  justify-between my-7  items-center gap-4">
                    <div className=" flex justify-between items-center gap-4">
                      <img
                        src={ imagePath+ items.image}
                        width={20}
                        height={20}
                      />
                      {items.name}
                    </div>
                    
                  </li>
                </Link>
              );
            })}
          </ul>
        </div>
        <div className=" relative h-[456px] w-[969px] ">
          <img
            src="/hero.png"
            alt=""
            className="w-full h-full object-cover rounded-3xl"
          />
          <div className="top-0 absolute px-20 py-10 leading-tight ">
            <div className="text-[72px] font-bold text-white">
              Don’t miss amazing <br /> grocery deals
            </div>
            <p className="text-xl py-10 font-semibold text-white font-serif ">
              Sign up for the daily newsletter
            </p>
            <div className=" my-6 flex border w-fit items-center rounded-4xl  text-white border-gray-400 bg-transparent ps-4">
              <div className="flex items-center gap-3 pe-5">
                <div className="text-xl">
                  <IoMdShareAlt />
                </div>
                <div>Your email address</div>
              </div>
              <div className=" py-4 px-8 rounded-4xl bg-sky-400">Subscribe</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
