import Image from "next/image";
import ProductCard from "../Store/ProductCard";
import { getProduct } from "@/api_call/api";

export default async function MultiTabs() {
  const Products_res = await  getProduct()
  const products = Products_res?.data;
  return (
    <div className="max-w-7xl mt-2 mx-auto bg-gray-100 rounded-2xl p-6">
      {/* Tabs Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex gap-6 text-sm font-medium">
          <span className="text-black">BEST SELLER</span>
          <span className="text-gray-500">NEW IN</span>
          <span className="text-gray-500">POPULAR</span>
        </div>
        <span className="text-xs text-gray-500 cursor-pointer">View All</span>
      </div>

      {/* Products Row */}
      <div className="grid grid-cols-4 gap-5 ">
      {
        products.map((items)=>{
          return(
            <ProductCard key={items._id} items = {items}/>
          )
        })
      }
      </div>
     
    </div>
  );
}
