import { getBrand } from "@/api_call/api";
import React from "react";
import Link from "next/link";
export default async function FeatureBrand() {
const brand_res = await getBrand();
const brand = brand_res?.data;
const imagePath = brand_res?.data?.meta?.imagebaseurl;

  return (
    <div className="py-10 px-6 bg-white rounded-4xl shadow-xl ">
      <h1 className="text-xl mb-10 font-bold text-black">FEATURED BRANDS</h1>
      <div className=" ps-5  grid  grid-cols-5 gap-5 items-center ">
        {brand.map((item, index) => {
          // console.log(item.image)
          return (
            <div
            key={index}
            className="flex flex-col items-center justify-between  text-center"
          >
              <Link href={"/"} >
              <img
              src={`http://localhost:5000/brand/${item.image}`}
              alt="brand"
              className="h-10 rounded-xl object-contain"
            />
              </Link>
            <Link href="/" className="mt-2 font-semibold hover:bg-gray-200 rounded-2xl p-1">{item.name}</Link>
          </div>

          );
        })}
      </div>
    </div>
  );
}
